={{
(() => {
  const bp = $("Breakpoint - Inspect Slack Reply").first().json;

  const verdict = (bp.verdict || "").toLowerCase();

  const originalReply =
    $("Build Breakpoint Payload").first().json.payload.text;

  const safeReply =
    verdict === "mask" || verdict === "fix"
      ? bp.modified_payload?.text ||
        bp.clean_payload?.text ||
        bp.payload?.text ||
        originalReply
      : originalReply;

  return {
    channel: $("Fake Slack Message").first().json.channel_id,
    text:
      `🛡️ *Breakpoint checked this AI reply before posting*\n` +
      `*Verdict:* ${bp.verdict || "unknown"} | *Risk:* ${bp.risk_level || "unknown"} | *Score:* ${bp.score ?? "n/a"}\n\n` +
      safeReply
  };
})()
}}

parameters.jsCode:
const bp = $('Breakpoint - Inspect Slack Reply').first().json;
const built = $('Build Breakpoint Payload').first().json;
const slack = $json;

const finalReply =
  ((bp.verdict || '').toLowerCase() === 'mask' || (bp.verdict || '').toLowerCase() === 'fix')
    ? (bp.modified_payload?.text || bp.clean_payload?.text || bp.payload?.text || built.payload.text)
    : built.payload.text;

return [
  {
    json: {
      demo_result: slack.ok === true ? "POSTED_TO_SLACK" : "SLACK_POST_ATTEMPTED_CHECK_RESPONSE",
      slack_ok: slack.ok,
      slack_error: slack.error || null,
      verdict: bp.verdict,
      risk_level: bp.risk_level || bp.riskLevel || null,
      score: bp.score || bp.safety_score || null,
      rules_fired: bp.rules_fired || bp.rulesFired || bp.rule_fired || [],
      original_ai_reply: built.payload.text,
      final_posted_reply: finalReply,
      event_id: bp.event_id || null,
      openai_refused_or_empty: built._demo.openai_refused_or_empty,
      action_taken:
        ((bp.verdict || '').toLowerCase() === 'mask')
          ? "Risky Slack reply inspected and masked before posting"
          : ((bp.verdict || '').toLowerCase() === 'fix')
            ? "Risky Slack reply inspected and fixed before posting"
            : "Slack reply allowed and posted"
    }
  }
];

const bp = $('Breakpoint - Inspect Slack Reply').first().json;
const built = $('Build Breakpoint Payload').first().json;

return [
  {
    json: {
      demo_result: "BLOCKED_NOT_POSTED_TO_SLACK",
      verdict: bp.verdict,
      risk_level: bp.risk_level || bp.riskLevel || null,
      score: bp.score || bp.safety_score || null,
      rules_fired: bp.rules_fired || bp.rulesFired || bp.rule_fired || [],
      blocked_reply: built.payload.text,
      reason: bp.reason || "Breakpoint returned block verdict",
      event_id: bp.event_id || null,
      openai_refused_or_empty: built._demo.openai_refused_or_empty,
      action_taken: "Reply was blocked. Nothing was posted to Slack."
    }
  }
];
